import Vue from 'vue'
import Router from 'vue-router'
import HomePage from '../views/HomePage.vue'
import StatsPage from '../views/StatsPage.vue'

Vue.use(Router)

const routes = [
  {
    path: '/',
    name: 'Home',
    component: HomePage
  },
  {
    path: '/stats',
    name: 'Stats',
    component: StatsPage
  }
]

const router = new Router({
  mode: 'history',
  routes
})

export default router
